SELECT name, capital, population_2002
FROM territories
ORDER BY population_2002 DESC;

SELECT t.name, t.population_growth_rate 
FROM territories t 
WHERE t.population_growth_rate > (SELECT AVG(population_growth_rate) FROM territories);

SELECT user_name, role
FROM users
WHERE role = 'researcher' AND country_access LIKE '%Finland%';

SELECT name, population_2002
FROM territories
WHERE region = 'Asia';

SELECT name
FROM territories
WHERE population_growth_rate > (SELECT AVG(population_growth_rate) FROM territories);

SELECT AVG(population_2002) AS average_population_2002
FROM territories
WHERE country_id = 0;
